import axios from 'axios';

const API_BASE_URL = 'http://localhost:8080/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  timeout: 10000,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Request interceptor
api.interceptors.request.use(
  (config) => {
    console.log(`API Request: ${config.method?.toUpperCase()} ${config.url}`);
    return config;
  },
  (error) => {
    console.error('API Request Error:', error);
    return Promise.reject(error);
  }
);

// Response interceptor
api.interceptors.response.use(
  (response) => {
    console.log(`API Response: ${response.config.method?.toUpperCase()} ${response.config.url} - Status: ${response.status}`);
    return response;
  },
  (error) => {
    console.error('API Response Error:', error.response?.data || error.message);
    return Promise.reject(error);
  }
);

// Complaint Management APIs
export const complaintAPI = {
  // Start a new complaint process
  startComplaint: (complaintData) => {
    return api.post('/complaints/start', complaintData);
  },

  // Get tasks with optional filtering
  getTasks: (params = {}) => {
    return api.get('/tasks', { params });
  },

  // Get enriched tasks with detailed information
  getEnrichedTasks: (params = {}) => {
    return api.get('/tasks/enriched', { params });
  },

  // Get task variables
  getTaskVariables: (taskId) => {
    return api.get(`/tasks/${taskId}/variables`);
  },

  // Claim a task
  claimTask: (taskId, userId) => {
    return api.post(`/tasks/${taskId}/claim`, { userId });
  },

  // Complete a task with variables
  completeTask: (taskId, variables = {}) => {
    return api.post(`/tasks/${taskId}/complete`, { variables });
  },

  // Get process information
  getProcess: (instanceId) => {
    return api.get(`/process/${instanceId}`);
  },
};

// Helper functions for common operations
export const taskHelpers = {
  // Get tasks for a specific candidate group
  getTasksByGroup: (candidateGroup) => {
    return complaintAPI.getEnrichedTasks({ candidateGroup });
  },

  // Get tasks assigned to a specific user
  getTasksByAssignee: (assignee) => {
    return complaintAPI.getEnrichedTasks({ assignee });
  },

  // Filter tasks by SLA status
  getTasksBySLA: (slaFilter) => {
    return complaintAPI.getEnrichedTasks({ slaFilter });
  },

  // Filter tasks by priority
  getTasksByPriority: (priorityFilter) => {
    return complaintAPI.getEnrichedTasks({ priorityFilter });
  },

  // Filter tasks by state
  getTasksByState: (stateFilter) => {
    return complaintAPI.getEnrichedTasks({ stateFilter });
  },
};

export default api;
